generated_oml:
// C3: Physical sensing components
instance MotorSideEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor‑side position encoder providing angular position and velocity of the permanent‑magnet synchronous motor."
    DTDFVocab:producedData MotorSideEncoderDataTransmitted
]

instance GearboxSideEncoder : DTDFVocab:SensingComponent [
    base:desc "Gearbox‑side position encoder providing angular position and velocity after the gearwheel gearbox."
    DTDFVocab:producedData GearboxSideEncoderDataTransmitted
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor (I_M) delivering real‑time current measurements of the motor drive."
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

// C4: Physical‑to‑virtual interaction (Data transmitted)
instance MotorSideEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorSideEncoder
]

instance GearboxSideEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxSideEncoder
]

instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C10: Data (sensor traces)
instance MotorSideEncoderData : DTDFVocab:Data [
    base:desc "Time‑series of motor‑side encoder angle and derived angular velocity ω_M."
    DTDFVocab:fromData MotorSideEncoderDataTransmitted
    DTDFVocab:inputTo MQTTBroker, SimulinkSimulationEngine
]

instance GearboxSideEncoderData : DTDFVocab:Data [
    base:desc "Time‑series of gearbox‑side encoder angle and derived angular velocity ω_G."
    DTDFVocab:fromData GearboxSideEncoderDataTransmitted
    DTDFVocab:inputTo MQTTBroker, SimulinkSimulationEngine
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Time‑series of motor drive current I_M."
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo MQTTBroker, SimulinkSimulationEngine
]

// C11: Enablers (tooling and infrastructure)
instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker used for streaming live sensor time‑series (current, encoder angles) from the robot to the digital shadow."
    DTDFVocab:enables FrictionIdentificationService, DataVisualizationService
]

instance SimulinkSimulationEngine : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink execution environment running friction‑free drivetrain and friction models (Coulomb‑Viscous, Stribeck, Dahl, LuGre)."
    DTDFVocab:enables FrictionIdentificationService, FrictionParameterUpdateService
]

instance DashboardVisualization : DTDFVocab:Enabler [
    base:desc "Custom web dashboard visualising measured and simulated data streams in real time."
    DTDFVocab:enables DataVisualizationService
]

instance SysMLModelingTool : DTDFVocab:Enabler [
    base:desc "SysML tool (block definition and internal block diagrams) for structural and behavioral engineering models of the axis."
    DTDFVocab:enables DataVisualizationService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell (AAS) providing standardized model integration and metadata exposure."
    DTDFVocab:enables FrictionParameterUpdateService
]

// C6: Services (DT services)
instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Real‑time identification of static, kinetic and viscous friction coefficients for the gearbox."
    DTDFVocab:provides FrictionParameterInsight
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Unified visualization of measured sensor data and simulated model outputs."
    DTDFVocab:provides PositioningErrorReductionInsight
]

instance FrictionParameterUpdateService : DTDFVocab:Service [
    base:desc "Generation and transmission of updated friction parameters back to the robot controller to improve model‑based motion control."
    DTDFVocab:provides UpdateFrictionParametersAction
]

// C17: Insights
instance FrictionParameterInsight : DTDFVocab:Insight [
    base:desc "Derived friction parameters (static, kinetic, viscous coefficients) are fed back to the controller to enhance model‑based control, reducing positioning errors."
]

instance PositioningErrorReductionInsight : DTDFVocab:Insight [
    base:desc "Visualization confirms that updated friction parameters decrease the robot's positioning error during machining."
]

// C17: Actions
instance UpdateFrictionParametersAction : DTDFVocab:Action [
    base:desc "Transmit the newly identified friction coefficients to the robot controller for immediate use in motion planning."
    DTDFVocab:IsAutomatic true
]

// C10: Engineering and Simulation Models
instance SysMLAxisModel : DTDFVocab:Model [
    base:desc "SysML block definition and internal block diagrams describing the motor, gearwheel gearbox and cycloidal gearbox of the first vertical axis."
    DTDFVocab:inputTo AssetAdministrationShell
]

instance SimulinkFrictionFreeDrivetrainModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model of the friction‑free drivetrain used as a baseline for identification."
    DTDFVocab:inputTo SimulinkSimulationEngine
]

instance SimulinkCoulombViscousModel : DTDFVocab:Model [
    base:desc "Simulink implementation of a Coulomb‑Viscous friction model."
    DTDFVocab:inputTo SimulinkSimulationEngine
]

instance SimulinkStribeckModel : DTDFVocab:Model [
    base:desc "Simulink implementation of a Stribeck friction model."
    DTDFVocab:inputTo SimulinkSimulationEngine
]

instance SimulinkDahlModel : DTDFVocab:Model [
    base:desc "Simulink implementation of a Dahl friction model."
    DTDFVocab:inputTo SimulinkSimulationEngine
]

instance SimulinkLuGreModel : DTDFVocab:Model [
    base:desc "Simulink implementation of a LuGre friction model."
    DTDFVocab:inputTo SimulinkSimulationEngine
]

// C14: Environment and Physical Components (system under study)
instance RobotAxisEnvironment : DTDFVocab:Environment [
    base:contains PermanentMagnetSynchronousMotor, GearwheelGearbox, CycloidalGearbox
]

instance PermanentMagnetSynchronousMotor : DTDFVocab:Component [
    base:desc "Permanent‑magnet synchronous motor driving the first vertical axis of the MABI MAX 100 robot."
]

instance GearwheelGearbox : DTDFVocab:Component [
    base:desc "Standard gearwheel gearbox located between the motor and the cycloidal gearbox."
]

instance CycloidalGearbox : DTDFVocab:Component [
    base:desc "Cycloidal gearbox used for high‑precision machining operations on the first vertical axis."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "The digital shadow operates in real‑time during robot execution. Sensor measurements are captured continuously as time‑series and processed on‑the‑fly by simulation and calculation models, enabling online friction identification and immediate availability of results for the current operating cycle."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A purpose‑driven digital shadow comprising the asset (first axis), sources (sensor channels), processing components (simulation models), data traces (measured and simulated), and a dashboard; all instantiated as concrete classes conforming to the Digital Shadow Reference Model."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The digital shadow is created for the operational stage of the robot, using live data to continuously identify friction during runtime."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Traceability of each DataTrace to its originating sensor and processing model; comparison of simulated friction‑free and friction‑augmented outputs against measured references to assess model accuracy; continuous updating of white‑ and black‑box friction parameters to maintain validity over wear."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data are transmitted from the robot to the digital shadow via MQTT; the Asset Administration Shell defines the metadata and interfaces for the models; processing components consume MQTT streams and produce data for the dashboard."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The implementation leverages the Asset Administration Shell (an Industry 4.0 standard) and SysML (OMG standard) for model definition and data exchange."
]
